select qbq.*, qb.title as bankTitle, q.title as questionTitle from question_bank_question qbq left join question_bank qb on qbq.question_bank_id = qb.id left join interview_question q on qbq.question_id = q.id
and qbq.question_bank_id = #{questionBankId} and qbq.question_id = #{questionId}
order by qbq.sort_order asc, qbq.id asc

select * from question_bank_question
where question_bank_id = #{questionBankId} and question_id = #{questionId}
limit 1

